trait TestTrait {
    fn run(&self);
}

macro_rules! test_macro {
    ($name:ident) => {
        struct $name;
        impl TestTrait for $name {
            fn run(&self) { // Add &self parameter to match trait signature
                println!("Running {}", stringify!($name));
            }
        }
    };
}

fn main() {
    test_macro!(MyTest);
}

